mapper.select:
select * from
reginfotable,busertable,testinfo__room,roomtable,testinfotable,testtable
where reginfotable.user_id=busertable.user_id and
reginfotable.testinfo__room_id=testinfo__room.testinfo__room_id and
testinfo__room.room_id=roomtable.room_id and
testinfo__room.testinfo_id = testinfotable.testinfo_id and
testinfotable.test_id = testtable.test_id and ""=""

	and reginfo_id = #{reginfo_id}


	and tname = #{tname}


	and uname = #{uname}


	and rname = #{rname}
